css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0a0e1a; color: white; }
.layout { display: flex; min-height: 100vh; }
.sidebar { width: 220px; background: #0f1320; border-right: 1px solid rgba(255,255,255,0.06); padding: 28px 18px; flex-shrink: 0; }
.logo { font-size: 18px; font-weight: 800; margin-bottom: 32px; padding-left: 8px; }
nav { display: flex; flex-direction: column; gap: 4px; }
nav a { display: flex; align-items: center; gap: 12px; padding: 11px 12px; border-radius: 10px; color: rgba(255,255,255,0.5); font-size: 14px; font-weight: 600; cursor: pointer; text-decoration: none; }
nav a span { font-size: 16px; }
nav a.active { background: rgba(168,85,247,0.12); color: #c084fc; }
.content { flex: 1; padding: 32px 36px; max-width: 1200px; }
header { display: flex; justify-content: space-between; align-items: flex-end; margin-bottom: 22px; flex-wrap: wrap; gap: 12px; }
header h1 { font-size: 26px; font-weight: 800; }
header p { color: rgba(255,255,255,0.4); font-size: 13px; margin-top: 4px; }
.new-task { background: linear-gradient(135deg, #a855f7, #7c3aed); border: none; color: white; padding: 12px 22px; border-radius: 12px; font-size: 13.5px; font-weight: 700; cursor: pointer; box-shadow: 0 10px 25px rgba(168,85,247,0.3); }
.stats { display: grid; grid-template-columns: repeat(auto-fit, minmax(140px, 1fr)); gap: 14px; margin-bottom: 22px; }
.stat { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 16px; padding: 18px 20px; display: flex; flex-direction: column; gap: 6px; }
.stat .value { font-size: 24px; font-weight: 800; }
.stat .label { color: rgba(255,255,255,0.4); font-size: 12.5px; font-weight: 600; }
.board { display: grid; grid-template-columns: repeat(3, 1fr); gap: 16px; }
.column { background: rgba(255,255,255,0.02); border: 1px solid rgba(255,255,255,0.06); border-radius: 16px; padding: 16px; min-height: 200px; }
.column-head { display: flex; align-items: center; gap: 10px; font-size: 13.5px; font-weight: 700; color: rgba(255,255,255,0.75); margin-bottom: 14px; }
.dot { width: 9px; height: 9px; border-radius: 50%; }
.dot.todo { background: #818cf8; }
.dot.progress { background: #facc15; }
.dot.done { background: #4ade80; }
.count { margin-left: auto; background: rgba(255,255,255,0.06); color: rgba(255,255,255,0.5); font-size: 11px; padding: 2px 8px; border-radius: 999px; }
.card { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.06); border-radius: 12px; padding: 14px; margin-bottom: 12px; cursor: grab; }
.card:active { opacity: 0.6; }
.card p { font-size: 13.5px; color: rgba(255,255,255,0.85); margin: 10px 0 12px; line-height: 1.4; }
.tag { font-size: 10.5px; font-weight: 700; padding: 3px 9px; border-radius: 999px; }
.tag-design { background: rgba(244,114,182,0.15); color: #f472b6; }
.tag-dev { background: rgba(99,102,241,0.15); color: #818cf8; }
.tag-marketing { background: rgba(34,197,94,0.15); color: #4ade80; }
.card-foot { display: flex; justify-content: space-between; align-items: center; }
.avatar { width: 26px; height: 26px; border-radius: 50%; background: linear-gradient(135deg, #a855f7, #6366f1); display: flex; align-items: center; justify-content: center; font-size: 10px; font-weight: 700; }
.due { font-size: 11.5px; color: rgba(255,255,255,0.4); font-weight: 600; }
.progress-bar { height: 6px; background: rgba(255,255,255,0.06); border-radius: 999px; overflow: hidden; margin-bottom: 10px; }
.progress-bar div { height: 100%; background: linear-gradient(90deg, #facc15, #f97316); border-radius: 999px; }
.done-card { opacity: 0.7; }
.check { font-size: 11.5px; color: #4ade80; font-weight: 700; }
@media (max-width: 900px) { .layout { flex-direction: column; } .sidebar { width: 100%; display: flex; } nav { flex-direction: row; overflow-x: auto; } .board { grid-template-columns: 1fr; } }

